     1→// FreeLang v6: Bytecode Compiler
     2→
     3→import { Expr, Stmt, Program, MatchArm } from "./ast";
     4→
     5→export enum Op {
     6→  Const, Pop, Dup,
     7→  Add, Sub, Mul, Div, Mod, Neg,
     8→  Eq, Neq, Lt, Gt, Lte, Gte,
     9→  And, Or, Not,
    10→  Jump, JumpIfFalse, JumpIfTrue,
    11→  Load, Store, LoadGlobal, StoreGlobal,
    12→  Call, Return, Builtin,
    13→  NewArray, Index, SetIndex,
    14→  NewObject, GetProp, SetProp,
    15→  NewClosure, LoadFree, StoreFree,
    16→  Print, Println,
    17→  TryBegin, TryEnd, Throw,
    18→  Iter, IterNext, IterDone,
    19→  AddrOf, Deref,  // v5.9.1: Pointer operators
    20→  // Phase 4: Unsafe 격리 레이어
    21→  Malloc, Free, Realloc,
    22→  UnsafeRead, UnsafeWrite,
    23→  UnsafeBegin, UnsafeEnd,
    24→  Halt,
    25→}
    26→
    27→export type Value =
    28→  | { tag: "num"; val: number }
    29→  | { tag: "str"; val: string }
    30→  | { tag: "bool"; val: boolean }
    31→  | { tag: "null" }
    32→  | { tag: "array"; val: Value[] }
    33→  | { tag: "object"; val: Map<string, Value> }
    34→  | { tag: "fn"; name: string; arity: number; addr: number; freeVars: Value[] }
    35→  | { tag: "builtin"; name: string }
    36→  | { tag: "iter"; val: Value[]; idx: number }
    37→  | { tag: "ptr"; addr: number; target?: Value }; // Pointer type (v5.9.1) - STEP 1: target is optional for HeapManager
    38→
    39→export type Chunk = {
    40→  code: number[];
    41→  constants: Value[];
    42→  lines: number[];
    43→};
    44→
    45→type Local = { name: string; depth: number };
    46→type Upvalue = { name: string; isLocal: boolean; index: number };
    47→type CompilerScope = {
    48→  locals: Local[];
    49→  depth: number;
    50→  upvalues: Upvalue[];
    51→};
    52→
    53→type LoopInfo = { startAddr: number; breakPatches: number[] };
    54→
    55→export function compile(program: Program): Chunk {
    56→  const chunk: Chunk = { code: [], constants: [], lines: [] };
    57→  const scopes: CompilerScope[] = [{ locals: [], depth: 0, upvalues: [] }];
    58→  const globals = new Set<string>();
    59→  const loopStack: LoopInfo[] = [];
    60→  const finallyStack: Stmt[][] = [];
    61→
    62→  function emit(op: Op, line = 0) { chunk.code.push(op); chunk.lines.push(line); }
    63→  function emitArg(op: Op, arg: number, line = 0) { emit(op, line); chunk.code.push(arg); chunk.lines.push(line); }
    64→  function addConst(val: Value): number {
    65→    chunk.constants.push(val);
    66→    return chunk.constants.length - 1;
    67→  }
    68→  function currentPos(): number { return chunk.code.length; }
    69→  function patchJump(pos: number) { chunk.code[pos + 1] = currentPos(); }
    70→
    71→  function scope(): CompilerScope { return scopes[scopes.length - 1]; }
    72→
    73→  function resolveLocal(name: string): number {
    74→    const locals = scope().locals;
    75→    for (let i = locals.length - 1; i >= 0; i--) {
    76→      if (locals[i].name === name) return i;
    77→    }
    78→    return -1;
    79→  }
    80→
    81→  function declareLocal(name: string) {
    82→    scope().locals.push({ name, depth: scope().depth });
    83→  }
    84→
    85→  function resolveUpvalue(name: string): number {
    86→    if (scopes.length < 2) return -1;
    87→    const s = scope();
    88→    for (let i = 0; i < s.upvalues.length; i++) {
    89→      if (s.upvalues[i].name === name) return i;
    90→    }
    91→    const parent = scopes[scopes.length - 2];
    92→    for (let j = parent.locals.length - 1; j >= 0; j--) {
    93→      if (parent.locals[j].name === name) {
    94→        s.upvalues.push({ name, isLocal: true, index: j });
    95→        return s.upvalues.length - 1;
    96→      }
    97→    }
    98→    for (let j = 0; j < parent.upvalues.length; j++) {
    99→      if (parent.upvalues[j].name === name) {
   100→        s.upvalues.push({ name, isLocal: false, index: j });
   101→        return s.upvalues.length - 1;
   102→      }
   103→    }
   104→    return -1;
   105→  }
   106→
   107→  function compileStmts(stmts: Stmt[]) {
   108→    for (const s of stmts) compileStmt(s);
   109→  }
   110→
   111→  // Compile statements where the last expr must leave a value on the stack
   112→  function compileStmtsAsExpr(stmts: Stmt[]) {
   113→    for (let i = 0; i < stmts.length; i++) {
   114→      const s = stmts[i];
   115→      const isLast = i === stmts.length - 1;
   116→
   117→      if (isLast && s.kind === "expr") {
   118→        // Last statement is an expression: compile it but DON'T pop
   119→        compileExpr(s.expr);
   120→      } else if (isLast && s.kind === "if") {
   121→        // Last statement is an if-statement in expression context
   122→        // Both branches must leave values on the stack
   123→        compileExpr(s.cond);
   124→        const jumpFalse = currentPos(); emitArg(Op.JumpIfFalse, 0);
   125→        compileStmtsAsExpr(s.then);
   126→        if (s.else) {
   127→          const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   128→          patchJump(jumpFalse);
   129→          compileStmtsAsExpr(s.else);
   130→          patchJump(jumpEnd);
   131→        } else {
   132→          // If-statement without else in expression context: push null as default
   133→          emitArg(Op.Const, addConst({ tag: "null" }));
   134→          const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   135→          patchJump(jumpFalse);
   136→          patchJump(jumpEnd);
   137→        }
   138→      } else {
   139→        compileStmt(s);
   140→      }
   141→    }
   142→  }
   143→
   144→  function compileStmt(s: Stmt) {
   145→    switch (s.kind) {
   146→      case "expr": compileExpr(s.expr); emit(Op.Pop); break;
   147→      case "let": {
   148→        if (scope().depth === 0) {
   149→          globals.add(s.name);
   150→          if (s.init) compileExpr(s.init); else emitArg(Op.Const, addConst({ tag: "null" }));
   151→          emitArg(Op.StoreGlobal, addConst({ tag: "str", val: s.name }));
   152→        } else {
   153→          declareLocal(s.name);
   154→          if (s.init) compileExpr(s.init); else emitArg(Op.Const, addConst({ tag: "null" }));
   155→          // Store the value in the local variable slot
   156→          emitArg(Op.Store, scope().locals.length - 1);
   157→        }
   158→        break;
   159→      }
   160→      case "fn": {
   161→        if (scope().depth === 0) globals.add(s.name);
   162→        else declareLocal(s.name);
   163→        compileFnBody(s.name, s.params, s.body);
   164→        if (scope().depth === 0) {
   165→          emitArg(Op.StoreGlobal, addConst({ tag: "str", val: s.name }));
   166→        }
   167→        break;
   168→      }
   169→      case "return": {
   170→        // Emit any pending finally blocks first
   171→        for (const fb of [...finallyStack].reverse()) {
   172→          compileStmts(fb);
   173→        }
   174→        if (s.value) compileExpr(s.value); else emitArg(Op.Const, addConst({ tag: "null" }));
   175→        emit(Op.Return);
   176→        break;
   177→      }
   178→      case "if": {
   179→        compileExpr(s.cond);
   180→        const jumpFalse = currentPos(); emitArg(Op.JumpIfFalse, 0);
   181→        compileStmts(s.then);
   182→        if (s.else) {
   183→          const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   184→          patchJump(jumpFalse);
   185→          compileStmts(s.else);
   186→          patchJump(jumpEnd);
   187→        } else {
   188→          patchJump(jumpFalse);
   189→        }
   190→        break;
   191→      }
   192→      case "while": {
   193→        const loop: LoopInfo = { startAddr: currentPos(), breakPatches: [] };
   194→        loopStack.push(loop);
   195→        compileExpr(s.cond);
   196→        const exit = currentPos(); emitArg(Op.JumpIfFalse, 0);
   197→        compileStmts(s.body);
   198→        emitArg(Op.Jump, loop.startAddr);
   199→        patchJump(exit);
   200→        for (const bp of loop.breakPatches) patchJump(bp);
   201→        loopStack.pop();
   202→        break;
   203→      }
   204→      case "for": {
   205→        // Compile iterator expression, store as global __iter_N
   206→        compileExpr(s.iter);
   207→        emit(Op.Iter);
   208→        const iterName = `__iter_${currentPos()}`;
   209→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: iterName }));
   210→        const loop: LoopInfo = { startAddr: currentPos(), breakPatches: [] };
   211→        loopStack.push(loop);
   212→        // Check done
   213→        emitArg(Op.LoadGlobal, addConst({ tag: "str", val: iterName }));
   214→        emit(Op.IterDone);
   215→        const exit = currentPos(); emitArg(Op.JumpIfTrue, 0);
   216→        // Get next value, store as loop variable
   217→        emitArg(Op.LoadGlobal, addConst({ tag: "str", val: iterName }));
   218→        emit(Op.IterNext);
   219→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: s.name }));
   220→        compileStmts(s.body);
   221→        emitArg(Op.Jump, loop.startAddr);
   222→        patchJump(exit);
   223→        for (const bp of loop.breakPatches) patchJump(bp);
   224→        loopStack.pop();
   225→        break;
   226→      }
   227→      case "block": {
   228→        scope().depth++;
   229→        compileStmts(s.body);
   230→        const localsToRemove = scope().locals.filter(l => l.depth === scope().depth).length;
   231→        for (let i = 0; i < localsToRemove; i++) { emit(Op.Pop); scope().locals.pop(); }
   232→        scope().depth--;
   233→        break;
   234→      }
   235→      case "break": {
   236→        if (loopStack.length === 0) throw new Error("break outside loop");
   237→        const bp = currentPos(); emitArg(Op.Jump, 0);
   238→        loopStack[loopStack.length - 1].breakPatches.push(bp);
   239→        break;
   240→      }
   241→      case "continue": {
   242→        if (loopStack.length === 0) throw new Error("continue outside loop");
   243→        emitArg(Op.Jump, loopStack[loopStack.length - 1].startAddr);
   244→        break;
   245→      }
   246→      case "print": {
   247→        compileExpr(s.expr);
   248→        emit(s.newline ? Op.Println : Op.Print);
   249→        break;
   250→      }
   251→      case "try": {
   252→        // Push finally block to stack if present
   253→        if (s.finallyBody.length > 0) {
   254→          finallyStack.push(s.finallyBody);
   255→        }
   256→
   257→        const tryBegin = currentPos(); emitArg(Op.TryBegin, 0); // catch addr
   258→        compileStmts(s.body);  // return inside here will see finallyStack
   259→        emit(Op.TryEnd);
   260→
   261→        // Pop finally block from stack after compiling try body
   262→        if (s.finallyBody.length > 0) {
   263→          finallyStack.pop();
   264→        }
   265→
   266→        const jumpFinally = currentPos(); emitArg(Op.Jump, 0);
   267→        // Catch
   268→        patchJump(tryBegin);
   269→        if (s.catchVar) {
   270→          scope().depth++;
   271→          declareLocal(s.catchVar);
   272→          compileStmts(s.catchBody);
   273→          const localsToRemove = scope().locals.filter(l => l.depth === scope().depth).length;
   274→          for (let i = 0; i < localsToRemove; i++) { emit(Op.Pop); scope().locals.pop(); }
   275→          scope().depth--;
   276→        } else {
   277→          emit(Op.Pop); // discard error
   278→          compileStmts(s.catchBody);
   279→        }
   280→        // Finally
   281→        patchJump(jumpFinally);
   282→        compileStmts(s.finallyBody);
   283→        break;
   284→      }
   285→      case "throw": {
   286→        compileExpr(s.expr);
   287→        emit(Op.Throw);
   288→        break;
   289→      }
   290→      case "struct": {
   291→        // Store struct definition as global with type metadata
   292→        globals.add(s.name);
   293→
   294→        // Create struct object with field information
   295→        const structVal = new Map<string, Value>();
   296→
   297→        // Add each field with null default
   298→        for (const field of s.fields) {
   299→          structVal.set(field.name, { tag: "null" });
   300→        }
   301→
   302→        // Store field metadata as JSON
   303→        const fieldMetadata = s.fields.map(f => ({ name: f.name, type: f.type }));
   304→        structVal.set("__fields__", { tag: "str", val: JSON.stringify(fieldMetadata) });
   305→        structVal.set("__struct_name__", { tag: "str", val: s.name });
   306→
   307→        emitArg(Op.Const, addConst({ tag: "object", val: structVal }));
   308→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: s.name }));
   309→        break;
   310→      }
   311→      case "import": break; // handled by module loader
   312→      case "export": compileStmt(s.stmt); break; // compile inner stmt
   313→      case "multi": compileStmts(s.stmts); break;
   314→      case "match": {
   315→        // Compile subject once, store as temp global
   316→        compileExpr(s.subject);
   317→        const tempName = `__match_${currentPos()}`;
   318→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: tempName }));
   319→        const endPatches: number[] = [];
   320→        for (const arm of s.arms) {
   321→          if (arm.pattern !== null) {
   322→            emitArg(Op.LoadGlobal, addConst({ tag: "str", val: tempName }));
   323→            compileExpr(arm.pattern);
   324→            emit(Op.Eq);
   325→            const skip = currentPos(); emitArg(Op.JumpIfFalse, 0);
   326→            compileStmts(arm.body);
   327→            endPatches.push(currentPos()); emitArg(Op.Jump, 0);
   328→            patchJump(skip);
   329→          } else {
   330→            // Default arm (_)
   331→            compileStmts(arm.body);
   332→          }
   333→        }
   334→        const end = currentPos();
   335→        for (const p of endPatches) patchJump(p);
   336→        break;
   337→      }
   338→      case "if-let": {
   339→        // If let: pattern matching with optional else
   340→        compileExpr(s.value);
   341→        const tempName = `__iflet_${currentPos()}`;
   342→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: tempName }));
   343→
   344→        // Compare value with pattern
   345→        emitArg(Op.LoadGlobal, addConst({ tag: "str", val: tempName }));
   346→        compileExpr(s.pattern);
   347→        emit(Op.Eq);
   348→
   349→        const skipBody = currentPos();
   350→        emitArg(Op.JumpIfFalse, 0);
   351→
   352→        // Execute body
   353→        compileStmts(s.body);
   354→
   355→        const skipElse = currentPos();
   356→        emitArg(Op.Jump, 0);
   357→
   358→        // Execute else (if exists)
   359→        patchJump(skipBody);
   360→        if (s.else) {
   361→          compileStmts(s.else);
   362→        }
   363→
   364→        patchJump(skipElse);
   365→        break;
   366→      }
   367→      case "while-let": {
   368→        // While let: repeat while pattern matches
   369→        const loopStart = currentPos();
   370→
   371→        // Evaluate value
   372→        compileExpr(s.value);
   373→        const tempName = `__whilelet_${currentPos()}`;
   374→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: tempName }));
   375→
   376→        // Try to match pattern
   377→        emitArg(Op.LoadGlobal, addConst({ tag: "str", val: tempName }));
   378→        compileExpr(s.pattern);
   379→        emit(Op.Eq);
   380→
   381→        const exit = currentPos();
   382→        emitArg(Op.JumpIfFalse, 0);
   383→
   384→        // Execute body
   385→        compileStmts(s.body);
   386→
   387→        // Loop back
   388→        emitArg(Op.Jump, loopStart);
   389→
   390→        patchJump(exit);
   391→        break;
   392→      }
   393→    }
   394→  }
   395→
   396→  function compileFnBody(name: string, params: string[], body: Stmt[]) {
   397→    const jumpOver = currentPos(); emitArg(Op.Jump, 0);
   398→    const fnAddr = currentPos();
   399→    scopes.push({ locals: [], depth: 1, upvalues: [] });
   400→    for (const p of params) declareLocal(p);
   401→    // Compile body as expression: last stmt should leave value on stack
   402→    if (body.length === 0) {
   403→      emitArg(Op.Const, addConst({ tag: "null" }));
   404→    } else {
   405→      compileStmtsAsExpr(body);
   406→    }
   407→    emit(Op.Return);
   408→    const fnScope = scopes.pop()!;
   409→    patchJump(jumpOver);
   410→
   411→    if (fnScope.upvalues.length > 0) {
   412→      for (const uv of fnScope.upvalues) {
   413→        if (uv.isLocal) emitArg(Op.Load, uv.index);
   414→        else emitArg(Op.LoadFree, uv.index);
   415→      }
   416→      emitArg(Op.Const, addConst({ tag: "fn", name, arity: params.length, addr: fnAddr, freeVars: [] }));
   417→      emitArg(Op.NewClosure, fnScope.upvalues.length);
   418→    } else {
   419→      emitArg(Op.Const, addConst({ tag: "fn", name, arity: params.length, addr: fnAddr, freeVars: [] }));
   420→    }
   421→  }
   422→
   423→  function compileExpr(e: Expr) {
   424→    switch (e.kind) {
   425→      case "number": emitArg(Op.Const, addConst({ tag: "num", val: e.value })); break;
   426→      case "string": emitArg(Op.Const, addConst({ tag: "str", val: e.value })); break;
   427→      case "bool": emitArg(Op.Const, addConst({ tag: "bool", val: e.value })); break;
   428→      case "null": emitArg(Op.Const, addConst({ tag: "null" })); break;
   429→      case "ident": {
   430→        const local = resolveLocal(e.name);
   431→        if (local !== -1) { emitArg(Op.Load, local); break; }
   432→        const upval = resolveUpvalue(e.name);
   433→        if (upval !== -1) { emitArg(Op.LoadFree, upval); break; }
   434→        emitArg(Op.LoadGlobal, addConst({ tag: "str", val: e.name }));
   435→        break;
   436→      }
   437→      case "binary": {
   438→        compileExpr(e.left);
   439→        compileExpr(e.right);
   440→        const ops: Record<string, Op> = {
   441→          "+": Op.Add, "-": Op.Sub, "*": Op.Mul, "/": Op.Div, "%": Op.Mod,
   442→          "==": Op.Eq, "!=": Op.Neq, "<": Op.Lt, ">": Op.Gt, "<=": Op.Lte, ">=": Op.Gte,
   443→          "&&": Op.And, "||": Op.Or,
   444→        };
   445→        emit(ops[e.op]);
   446→        break;
   447→      }
   448→      case "unary": {
   449→        compileExpr(e.expr);
   450→        if (e.op === "-") emit(Op.Neg);
   451→        else if (e.op === "!" || e.op === "not") emit(Op.Not);
   452→        else if (e.op === "&") emit(Op.AddrOf);  // v5.9.1: Address-of operator
   453→        else if (e.op === "*") emit(Op.Deref);   // v5.9.1: Dereference operator
   454→        break;
   455→      }
   456→      case "call": {
   457→        compileExpr(e.callee); // Standard ident resolution: local → upvalue → global
   458→        for (const arg of e.args) compileExpr(arg);
   459→        emitArg(Op.Call, e.args.length);
   460→        break;
   461→      }
   462→      case "assign": {
   463→        compileExpr(e.value);
   464→        if (e.target.kind === "ident") {
   465→          const local = resolveLocal(e.target.name);
   466→          if (local !== -1) { emit(Op.Dup); emitArg(Op.Store, local); }
   467→          else {
   468→            const upval = resolveUpvalue(e.target.name);
   469→            if (upval !== -1) { emit(Op.Dup); emitArg(Op.StoreFree, upval); }
   470→            else { emit(Op.Dup); emitArg(Op.StoreGlobal, addConst({ tag: "str", val: e.target.name })); }
   471→          }
   472→        } else if (e.target.kind === "index") {
   473→          compileExpr(e.target.object);
   474→          compileExpr(e.target.index);
   475→          emit(Op.SetIndex);
   476→        } else if (e.target.kind === "member") {
   477→          compileExpr(e.target.object);
   478→          emitArg(Op.Const, addConst({ tag: "str", val: e.target.property }));
   479→          emit(Op.SetProp);
   480→        }
   481→        break;
   482→      }
   483→      case "array": {
   484→        for (const el of e.elements) compileExpr(el);
   485→        emitArg(Op.NewArray, e.elements.length);
   486→        break;
   487→      }
   488→      case "object": {
   489→        for (const { key, value } of e.entries) {
   490→          emitArg(Op.Const, addConst({ tag: "str", val: key }));
   491→          compileExpr(value);
   492→        }
   493→        emitArg(Op.NewObject, e.entries.length);
   494→        break;
   495→      }
   496→      case "index": {
   497→        compileExpr(e.object);
   498→        compileExpr(e.index);
   499→        emit(Op.Index);
   500→        break;
   501→      }
   502→      case "member": {
   503→        compileExpr(e.object);
   504→        emitArg(Op.GetProp, addConst({ tag: "str", val: e.property }));
   505→        break;
   506→      }
   507→      case "fn": {
   508→        compileFnBody(e.name ?? "<anon>", e.params, e.body);
   509→        break;
   510→      }
   511→      case "ternary": {
   512→        compileExpr(e.cond);
   513→        const jumpFalse = currentPos(); emitArg(Op.JumpIfFalse, 0);
   514→        compileExpr(e.then);
   515→        const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   516→        patchJump(jumpFalse);
   517→        compileExpr(e.else);
   518→        patchJump(jumpEnd);
   519→        break;
   520→      }
   521→      case "if": {
   522→        // If-expression: if cond { then_block } else { else_block }
   523→        // Both blocks must produce a value on the stack (don't pop last expr)
   524→        compileExpr(e.cond);
   525→        const jumpFalse = currentPos(); emitArg(Op.JumpIfFalse, 0);
   526→        compileStmtsAsExpr(e.then);
   527→        const jumpEnd = currentPos(); emitArg(Op.Jump, 0);
   528→        patchJump(jumpFalse);
   529→        compileStmtsAsExpr(e.else);
   530→        patchJump(jumpEnd);
   531→        break;
   532→      }
   533→      case "match": {
   534→        // Match expression: evaluate subject and match against patterns
   535→        compileExpr(e.subject);
   536→        const tempName = `__match_${currentPos()}`;
   537→        emitArg(Op.StoreGlobal, addConst({ tag: "str", val: tempName }));
   538→
   539→        const endPatches: number[] = [];
   540→        for (const arm of e.arms) {
   541→          if (arm.pattern !== null) {
   542→            // Load subject for comparison
   543→            emitArg(Op.LoadGlobal, addConst({ tag: "str", val: tempName }));
   544→
   545→            // Compile pattern and compare
   546→            compileExpr(arm.pattern);
   547→            emit(Op.Eq);
   548→
   549→            // If guard exists, add it to the condition with AND
   550→            if (arm.guard) {
   551→              compileExpr(arm.guard);
   552→              emit(Op.And);
   553→            }
   554→
   555→            const skip = currentPos();
   556→            emitArg(Op.JumpIfFalse, 0);
   557→
   558→            // Compile body as expression (preserve last value)
   559→            compileStmtsAsExpr(arm.body);
   560→
   561→            endPatches.push(currentPos());
   562→            emitArg(Op.Jump, 0);
   563→            patchJump(skip);
   564→          } else {
   565→            // Wildcard/default arm - always matches
   566→            if (arm.guard) {
   567→              // Even wildcard can have guard
   568→              compileExpr(arm.guard);
   569→              const skip = currentPos();
   570→              emitArg(Op.JumpIfFalse, 0);
   571→              compileStmtsAsExpr(arm.body);
   572→              endPatches.push(currentPos());
   573→              emitArg(Op.Jump, 0);
   574→              patchJump(skip);
   575→            } else {
   576→              // Default case - execute unconditionally
   577→              compileStmtsAsExpr(arm.body);
   578→            }
   579→          }
   580→        }
   581→
   582→        // Patch all end jumps
   583→        const end = currentPos();
   584→        for (const p of endPatches) patchJump(p);
   585→        break;
   586→      }
   587→    }
   588→  }
   589→
   590→  compileStmts(program.stmts);
   591→  emit(Op.Halt);
   592→  return chunk;
   593→}
