   178→      return this.stack.pop()!;
   179→    }
   180→    throw new Error(`Cannot call ${callee.tag}`);
   181→  }
   182→
   183→  /** Safe call for try_call builtin - captures errors as Value objects */
   184→  trySafeCall(callee: Value, args: Value[]): { ok: boolean; value?: Value; error?: Value } {
   185→    this.clearLastError();
   186→    this.inTryCall = true;
   187→
   188→    try {
   189→      if (callee.tag === "builtin") {
   190→        const retVal = this.builtinFns[callee.name](args, this);
