   401→                stackHeight: loopContext.stackHeightAtEntry,
   402→                globals: loopContext.globalSnapshotAtEntry,
   403→                locals: loopContext.localSnapshotAtEntry,
   404→              },
   405→              {
   406→                stackHeight: finalSnapshot.stackHeight,
   407→                globals: finalSnapshot.globals,
   408→                locals: finalSnapshot.locals,
   409→              }
   410→            );
   411→
   412→            if (this.traceMode) {
   413→              this.traceLogs.push(
   414→                `${indent}[JUMPIF] PC: ${this.ip-1} → ${addr} (condition FALSE, exit loop) | ` +
   415→                `Final iteration count: ${loopContext.iterationCount}`
   416→              );
   417→              this.traceLogs.push(
   418→                `${indent}  └─ Stack balanced: ${comparison.stackBalanced} | ` +
   419→                `Global changes: ${comparison.globalChanges.length} | ` +
   420→                `Local corruption: ${comparison.localChanges}`
   421→              );
   422→              for (const [varName, before, after] of comparison.globalChanges) {
   423→                this.traceLogs.push(
   424→                  `${indent}     ├─ ${varName}: ${this.stringify(before)} → ${this.stringify(after)}`
   425→                );
   426→              }
   427→            }
   428→
   429→            // Store state changes for later analysis
   430→            loopContext.stateChanges = comparison.globalChanges.map(([name, before, after]) => ({
   431→              varName: name,
   432→              before,
   433→              after,
   434→            }));
   435→
   436→            this.loopStack.pop();
   437→            this.loopDepth--;
   438→            if (this.traceMode) {
   439→              this.traceLogs.push(`${indent}  └─ Loop depth: ${this.loopDepth}`);
   440→            }
   441→          }
   442→          this.ip = addr;
   443→        } else {
   444→          // Loop condition TRUE = continue looping
   445→          if (this.traceMode) {
   446→            this.traceLogs.push(`${indent}[JUMPIF] PC: ${this.ip-1} (condition TRUE, continue loop)`);
   447→          }
   448→        }
   449→        break;
   450→      }
   451→      case Op.JumpIfTrue: { const addr = this.chunk.code[this.ip++]; if (this.truthy(this.pop())) this.ip = addr; break; }
