   453→      // Variables
   454→      case Op.Load: {
   455→        const slot = this.chunk.code[this.ip++];
   456→        const value = this.stack[this.baseSlot() + slot];
   457→        // STEP 4: 지역 변수를 Heap 기반으로 로드
   458→        this.stack.push(this.heapPtrToValue(this.valueToHeapPtr(value)));
