     1→/**
     2→ * FreeLang v6.3: Tail Call Optimization (TCO)
     3→ * 목표: SafeSum(100000, 0) = 5000050000을 O(1) 스택으로 실행
     4→ *
     5→ * 원리: 꼬리 재귀 = `return f(args)`가 마지막 연산일 때
     6→ *       스택 프레임 재사용 (새 push 없음) → 루프 변환
     7→ */
     8→
     9→export interface TailCallInfo {
    10→  funcName: string;                    // 재귀 호출되는 함수명
    11→  isSelfCall: boolean;                 // 자기 자신을 호출하는가
    12→  argCount: number;                    // 인자 수
    13→  position: "tail" | "non-tail";       // 꼬리 위치인가
    14→}
    15→
    16→/**
    17→ * Tail Call Detection: return f(args) 패턴 탐지
    18→ * 패턴 기반 분석 (AST 아님)
    19→ */
    20→export class TailCallDetector {
    21→  /**
    22→   * 함수가 꼬리 재귀 가능한지 판단
    23→   *
    24→   * 꼬리 재귀 = `return funcName(...)` 이 전체이고 AND
    25→   *           덧셈/뺄셈 등 후속 연산 없음
    26→   * (대소문자 무시)
    27→   */
    28→  isTailRecursive(funcName: string, body: string): boolean {
    29→    if (!body || body.trim() === "") return false;
    30→
    31→    // return 뒤에 함수 호출만 있는지 확인 (후속 연산 없음)
    32→    const lines = body.split("\n");
    33→    for (const line of lines) {
    34→      const trimmed = line.trim();
    35→
    36→      // "RETURN" 또는 "return"으로 시작하는지 확인
    37→      const returnMatch = trimmed.match(/^(return|RETURN)\s+(.+)$/i);
    38→      if (!returnMatch) continue;
    39→
    40→      const afterReturn = returnMatch[2]; // return 뒤의 전체 표현식
    41→
    42→      // 삼항 연산자 처리
    43→      if (afterReturn.includes("?")) {
    44→        // 삼항: "cond ? val : f(...)" 형태
    45→        const colonIndex = afterReturn.lastIndexOf(":");
    46→        if (colonIndex > 0) {
    47→          const elseBranch = afterReturn.substring(colonIndex + 1).trim();
    48→          // else 브랜치가 정확히 "funcName(...)" 형태인가?
    49→          const isTailInElse = new RegExp(
    50→            `^${funcName}\\s*\\([^)]*\\)\\s*$`,
    51→            "i"
    52→          ).test(elseBranch);
    53→          if (isTailInElse) {
    54→            return true; // tail call in else branch ✅
    55→          }
    56→        }
    57→      } else {
    58→        // 단순 return f(...) 형태
    59→        // "return funcName(...)" 가 전부인가?
    60→        // "return funcName(...) + x" 는 안 됨!
    61→        const isSingleTailCall = new RegExp(
    62→          `^${funcName}\\s*\\([^)]*\\)\\s*$`,
    63→          "i"
    64→        ).test(afterReturn);
    65→        if (isSingleTailCall) {
    66→          return true; // tail call ✅
    67→        }
    68→      }
    69→    }
    70→
    71→    return false;
    72→  }
    73→
    74→  /**
    75→   * body에서 모든 tail call 위치 찾기 (대소문자 무시)
    76→   */
    77→  detectTailCalls(funcName: string, body: string): TailCallInfo[] {
    78→    const calls: TailCallInfo[] = [];
    79→    if (!body) return calls;
    80→
    81→    // "return funcName(" 패턴 찾기 (모든 위치, 대소문자 무시)
    82→    const pattern = new RegExp(`(return|RETURN)\\s+${funcName}\\s*\\(([^)]*)\\)`, "gi");
    83→    let match;
    84→
    85→    while ((match = pattern.exec(body)) !== null) {
    86→      const argStr = match[2];
    87→      // 인자 개수: 쉼표로 분리
    88→      const argCount = argStr.trim() === "" ? 0 : argStr.split(",").length;
    89→
    90→      calls.push({
    91→        funcName,
    92→        isSelfCall: true,
    93→        argCount,
    94→        position: "tail",
    95→      });
    96→    }
    97→
    98→    return calls;
    99→  }
   100→
   101→  /**
   102→   * 단순 패턴: "return funcName(" 존재 여부 (대소문자 무시)
   103→   */
   104→  hasTailCallPattern(body: string, funcName: string): boolean {
   105→    if (!body || !funcName) return false;
   106→    const pattern = new RegExp(`(return|RETURN)\\s+${funcName}\\s*\\(`, "i");
   107→    return pattern.test(body);
   108→  }
   109→}
   110→
   111→/**
   112→ * TCO Engine: 꼬리 재귀를 루프로 실행
   113→ *
   114→ * 원리:
   115→ * - fn(args)가 배열 반환 → 다음 재귀 인자 (루프 계속)
   116→ * - fn(args)가 숫자 반환 → 최종 결과 (기저 조건, 루프 종료)
   117→ *
   118→ * 스택 깊이: 항상 1 (프레임 재사용!)
   119→ */
   120→export class TCOEngine {
   121→  private callDepth: number = 0;
   122→  private maxObservedDepth: number = 0;
   123→  private iterationCount: number = 0;
   124→
   125→  /**
   126→   * 꼬리 재귀 함수를 루프로 실행
   127→   *
   128→   * @param fn (args: number[]) => number[] | number
   129→   *   - 배열 반환: 다음 재귀 호출 인자 (꼬리 재귀 계속)
   130→   *   - 숫자 반환: 최종 결과 (기저 조건)
   131→   * @param initialArgs 초기 인자
   132→   * @returns 최종 결과값
   133→   *
   134→   * 예시: SafeSum(100000, 0)
   135→   * ```
   136→   * const safeSumFn = (args) => {
   137→   *   const [n, acc] = args;
   138→   *   if (n <= 0) return acc;  // 숫자 → 루프 종료
   139→   *   return [n - 1, acc + n]; // 배열 → 루프 계속
   140→   * };
   141→   * const result = engine.execute(safeSumFn, [100000, 0]);
   142→   * // result === 5000050000 ✅
   143→   * // callDepth === 1 ✅ (스택 폭발 없음!)
   144→   * ```
   145→   */
   146→  execute(
   147→    fn: (args: number[]) => number[] | number,
   148→    initialArgs: number[]
   149→  ): number {
   150→    // 초기화
   151→    this.callDepth = 1;  // 첫 호출은 깊이 1에서 시작
   152→    this.maxObservedDepth = 1;
   153→    this.iterationCount = 0;
   154→
   155→    let args = initialArgs;
   156→
   157→    // TCO 루프: 스택 깊이 항상 1
   158→    while (true) {
   159→      const result = fn(args);
   160→      this.iterationCount++;
   161→
   162→      if (typeof result === "number") {
   163→        // 기저 조건: 숫자 반환 → 최종값
   164→        this.callDepth = 0;
   165→        return result;
   166→      }
   167→
   168→      // 꼬리 재귀: 배열 반환 → 인자만 교체, 루프 계속
   169→      // 💡 중요: 스택 깊이는 1 그대로 (프레임 재사용!)
   170→      args = result;
   171→    }
   172→  }
   173→
   174→  /**
   175→   * 현재 콜 깊이 (TCO 중이면 항상 1, 실행 중 0)
   176→   */
   177→  getCurrentDepth(): number {
   178→    return this.callDepth;
   179→  }
   180→
   181→  /**
   182→   * 최대 관측 깊이 (TCO이면 항상 1)
   183→   */
   184→  getMaxObservedDepth(): number {
   185→    return this.maxObservedDepth;
   186→  }
   187→
   188→  /**
   189→   * 총 반복 횟수
   190→   */
   191→  getIterationCount(): number {
   192→    return this.iterationCount;
   193→  }
   194→
   195→  /**
   196→   * 초기화
   197→   */
   198→  reset(): void {
   199→    this.callDepth = 0;
   200→    this.maxObservedDepth = 0;
   201→    this.iterationCount = 0;
   202→  }
   203→}
   204→
   205→/**
   206→ * 사용 예시
   207→ *
   208→ * ```typescript
   209→ * // SafeSum 구현
   210→ * const safeSumFn = (args: number[]) => {
   211→ *   const [n, acc] = args;
   212→ *   if (n <= 0) return acc;         // 기저: 숫자 반환
   213→ *   return [n - 1, acc + n];        // 꼬리: 배열 반환
   214→ * };
   215→ *
   216→ * const engine = new TCOEngine();
   217→ * const result = engine.execute(safeSumFn, [100000, 0]);
   218→ *
   219→ * console.log(result);                   // 5000050000 ✅
   220→ * console.log(engine.getMaxObservedDepth()); // 1 ✅
   221→ * console.log(engine.getIterationCount());   // 100001 ✅
   222→ *
   223→ * // 탐지
   224→ * const detector = new TailCallDetector();
   225→ * const isSafeSumTCO = detector.isTailRecursive("SafeSum", safeSumBody);
   226→ * console.log(isSafeSumTCO); // true ✅
   227→ * ```
   228→ */
   229→

