     1→// FreeLang v5.9.3: Struct Packing Optimizer
     2→// 멤버 재배치를 통한 패딩 최소화
     3→
     4→export interface StructField {
     5→  name: string;
     6→  type: string;
     7→  originalOrder: number;
     8→}
     9→
    10→export interface OptimizedField extends StructField {
    11→  size: number;
    12→  align: number;
    13→  offset: number;
    14→  padding: number;
    15→}
    16→
    17→export interface StructOptimization {
    18→  originalSize: number;
    19→  optimizedSize: number;
    20→  savings: number;
    21→  fields: OptimizedField[];
    22→  reordered: boolean;
    23→}
    24→
    25→export class StructOptimizer {
    26→  /**
    27→   * Get size of a type string
    28→   */
    29→  private static getTypeSize(type: string): number {
    30→    const t = type.toLowerCase().trim();
    31→    const sizeMap: Record<string, number> = {
    32→      "i32": 4,
    33→      "i64": 8,
    34→      "f32": 4,
    35→      "f64": 8,
    36→      "bool": 1,
    37→      "byte": 1,
    38→      "char": 1,
    39→      "string": 16,
    40→      "any": 8,
    41→      "ptr": 4,
    42→      "null": 0,
    43→    };
    44→    return sizeMap[t] || 8;
    45→  }
    46→
    47→  /**
    48→   * Get alignment requirement of a type
    49→   */
    50→  private static getTypeAlign(type: string): number {
    51→    const t = type.toLowerCase().trim();
    52→    const alignMap: Record<string, number> = {
    53→      "i32": 4,
    54→      "i64": 8,
    55→      "f32": 4,
    56→      "f64": 8,
    57→      "bool": 1,
    58→      "byte": 1,
    59→      "char": 1,
    60→      "string": 4,
    61→      "any": 4,
    62→      "ptr": 4,
    63→      "null": 1,
    64→    };
    65→    return alignMap[t] || 4;
    66→  }
    67→
    68→  /**
    69→   * Align offset to next boundary
    70→   */
    71→  private static alignOffset(offset: number, alignment: number): number {
    72→    if (alignment <= 1) return offset;
    73→    const remainder = offset % alignment;
    74→    return remainder === 0 ? offset : offset + (alignment - remainder);
    75→  }
    76→
    77→  /**
    78→   * Calculate layout for field sequence
    79→   */
    80→  private static calculateLayout(
    81→    fields: StructField[]
    82→  ): { totalSize: number; optimized: OptimizedField[] } {
    83→    const optimized: OptimizedField[] = [];
    84→    let offset = 0;
    85→    let maxAlign = 1;
    86→
    87→    for (const field of fields) {
    88→      const size = this.getTypeSize(field.type);
    89→      const align = this.getTypeAlign(field.type);
    90→
    91→      // Calculate padding before this field
    92→      const alignedOffset = this.alignOffset(offset, align);
    93→      const padding = alignedOffset - offset;
    94→
    95→      optimized.push({
    96→        ...field,
    97→        size,
    98→        align,
    99→        offset: alignedOffset,
   100→        padding,
   101→      });
   102→
   103→      offset = alignedOffset + size;
   104→      maxAlign = Math.max(maxAlign, align);
   105→    }
   106→
   107→    // Tail padding to align structure size
   108→    const tailPadding = this.alignOffset(offset, maxAlign) - offset;
   109→    if (optimized.length > 0) {
   110→      optimized[optimized.length - 1].padding += tailPadding;
   111→    }
   112→
   113→    const totalSize = this.alignOffset(offset, maxAlign);
   114→
   115→    return { totalSize, optimized };
   116→  }
   117→
   118→  /**
   119→   * Optimize struct by reordering fields (greedy: largest alignment first)
   120→   */
   121→  static optimize(fields: StructField[]): StructOptimization {
   122→    // Calculate original layout (order-preserving)
   123→    const originalLayout = this.calculateLayout(fields);
   124→    const originalSize = originalLayout.totalSize;
   125→
   126→    // Sort fields by alignment requirement (descending) then size (descending)
   127→    const sortedFields = [...fields].sort((a, b) => {
   128→      const alignA = this.getTypeAlign(a.type);
   129→      const alignB = this.getTypeAlign(b.type);
   130→      const sizeA = this.getTypeSize(a.type);
   131→      const sizeB = this.getTypeSize(b.type);
   132→
   133→      // Primary: alignment (descending)
   134→      if (alignA !== alignB) return alignB - alignA;
   135→      // Secondary: size (descending)
   136→      return sizeB - sizeA;
   137→    });
   138→
   139→    // Calculate optimized layout
   140→    const optimizedLayout = this.calculateLayout(sortedFields);
   141→    const optimizedSize = optimizedLayout.totalSize;
   142→
   143→    const reordered = fields.some(
   144→      (f, i) => f.name !== sortedFields[i].name
   145→    );
   146→
   147→    return {
   148→      originalSize,
   149→      optimizedSize,
   150→      savings: originalSize - optimizedSize,
   151→      fields: optimizedLayout.optimized,
   152→      reordered,
   153→    };
   154→  }
   155→
   156→  /**
   157→   * Calculate total padding waste in a struct
   158→   */
   159→  static calculatePaddingWaste(fields: StructField[]): number {
   160→    const layout = this.calculateLayout(fields);
   161→    return layout.optimized.reduce((sum, f) => sum + f.padding, 0);
   162→  }
   163→
   164→  /**
   165→   * Get padding efficiency percentage
   166→   */
   167→  static getPaddingEfficiency(fields: StructField[]): number {
   168→    const layout = this.calculateLayout(fields);
   169→    const totalSize = layout.totalSize;
   170→    const dataSize = layout.optimized.reduce((sum, f) => sum + f.size, 0);
   171→    return totalSize > 0 ? Math.round((dataSize / totalSize) * 100) : 0;
   172→  }
   173→
   174→  /**
   175→   * Format field info for debugging
   176→   */
   177→  static formatFieldInfo(field: OptimizedField): string {
   178→    return `${field.name}(${field.type}): @${field.offset} [${field.size}B] +${field.padding}B pad`;
   179→  }
   180→
   181→  /**
   182→   * Generate optimization report
   183→   */
   184→  static generateReport(fields: StructField[]): string {
   185→    const opt = this.optimize(fields);
   186→    const lines: string[] = [];
   187→
   188→    lines.push("=== Struct Packing Report (v5.9.3) ===");
   189→    lines.push(`Original Size: ${opt.originalSize}B`);
   190→    lines.push(`Optimized Size: ${opt.optimizedSize}B`);
   191→    lines.push(`Savings: ${opt.savings}B (${Math.round((opt.savings / opt.originalSize) * 100)}%)`);
   192→    lines.push(`Reordered: ${opt.reordered ? "YES" : "NO"}`);
   193→    lines.push("");
   194→    lines.push("Field Layout:");
   195→
   196→    for (const field of opt.fields) {
   197→      lines.push(`  ${this.formatFieldInfo(field)}`);
   198→    }
   199→
   200→    return lines.join("\n");
   201→  }
   202→}
   203→

